	(2804,'_transient_dash_4077549d03da2e451c8b5f002294ff51','<div class=\"rss-widget\"><ul><li><a class=\'rsswidget\' href=\'https://wordpress.org/news/2016/03/wordpress-4-5-release-candidate/\'>WordPress 4.5 Release Candidate</a> <span class=\"rss-date\">24 marzo, 2016</span><div class=\"rssSummary\">The release candidate for WordPress 4.5 is now available. We’ve made 49 changes since releasing Beta 4 a week ago. RC means we think we’re done, but with millions of users and thousands of plugins and themes, it’s possible we’ve missed something. We hope to ship WordPress 4.5 on Tuesday, April 12, but we need your help [&hellip;]</div></li></ul></div><div class=\"rss-widget\"><ul><li><a class=\'rsswidget\' href=\'http://wptavern.com/draft-and-save-customizer-changes-for-later-with-new-customize-snapshots-plugin\'>WPTavern: Draft and Save Customizer Changes for Later with New Customize Snapshots Plugin</a></li><li><a class=\'rsswidget\' href=\'http://wptavern.com/get-your-widgets-ready-for-wordpress-4-5\'>WPTavern: Get Your Widgets Ready for WordPress 4.5</a></li><li><a class=\'rsswidget\' href=\'http://wptavern.com/versions-of-wp-cli-prior-to-0-23-0-are-incompatible-with-wordpress-4-5\'>WPTavern: Versions of WP-CLI Prior to 0.23.0 Are Incompatible with WordPress 4.5</a></li></ul></div><div class=\"rss-widget\"><ul><li class=\'dashboard-news-plugin\'><span>Plugin popular:</span> <a href=\'https://wordpress.org/plugins/siteorigin-panels/\' class=\'dashboard-news-plugin-link\'>Page Builder by SiteOrigin</a>&nbsp;<span>(<a href=\'plugin-install.php?tab=plugin-information&amp;plugin=siteorigin-panels&amp;_wpnonce=a0b593d2d3&amp;TB_iframe=true&amp;width=600&amp;height=800\' class=\'thickbox\' title=\'Page Builder by SiteOrigin\'>Instalar</a>)</span></li></ul></div>','no'),
