	(5830,'_transient_dash_3605f57d6641b1f6504fce9d39bcf566','<div class=\"rss-widget\"><ul><li><a class=\'rsswidget\' href=\'https://wordpress.org/news/2016/10/join-us-again-for-global-wordpress-translation-day/\'>Join Us Again for Global WordPress Translation Day</a> <span class=\"rss-date\">14 octubre, 2016</span><div class=\"rssSummary\">The WordPress Polyglots team is organizing the second Global WordPress Translation Day on November 12th. Everyone is invited to join – from anywhere in the world! Translating is one of the easiest ways to get involved with WordPress and contribute to the project. Global WordPress Translation Day is your chance to learn more about translating WordPress, meet [&hellip;]</div></li></ul></div><div class=\"rss-widget\"><ul><li><a class=\'rsswidget\' href=\'https://wptavern.com/wp-rest-api-content-endpoints-conditionally-approved-for-merge-in-4-7\'>WPTavern: WP REST API Content Endpoints Conditionally Approved for Merge in 4.7</a></li><li><a class=\'rsswidget\' href=\'https://wptavern.com/headway-3-8-9-patches-potential-xss-vulnerability\'>WPTavern: Headway 3.8.9 Patches Potential XSS Vulnerability</a></li><li><a class=\'rsswidget\' href=\'https://wptavern.com/studiopress-puts-woocommerce-compatibility-on-the-roadmap-for-new-themes\'>WPTavern: StudioPress Puts WooCommerce Compatibility on the Roadmap for New Themes</a></li></ul></div><div class=\"rss-widget\"><ul><li class=\'dashboard-news-plugin\'><span>Plugin popular:</span> <a href=\'https://wordpress.org/plugins/ml-slider/\' class=\'dashboard-news-plugin-link\'>Meta Slider</a>&nbsp;<span>(<a href=\'plugin-install.php?tab=plugin-information&amp;plugin=ml-slider&amp;_wpnonce=f46382ac69&amp;TB_iframe=true&amp;width=600&amp;height=800\' class=\'thickbox\' title=\'Meta Slider\'>Instalar</a>)</span></li></ul></div>','no'),
